    uint64_t t0 = ns();
    pthread_t a[th];
    for (size_t i = 0; i < th; i++) {
        pthread_create(&a[i], NULL, acquire_n, NULL);
    }
    for (size_t i = 0; i < th; i++) {
        pthread_join(a[i], NULL);
    }
    uint64_t t1 = ns();
    float t = (t1 - t0) / (float)(n * th);
    return t;
